import{_ as i,o,c as t,ai as a}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Thinking Levels","description":"","frontmatter":{"summary":"Directive syntax for /think + /verbose and how they affect model reasoning","read_when":["Adjusting thinking or verbose directive parsing or defaults"],"title":"Thinking Levels"},"headers":[],"relativePath":"tools/thinking.md","filePath":"tools/thinking.md","lastUpdated":1771906665000}'),s={name:"tools/thinking.md"};function l(n,e,d,r,h,c){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="thinking-levels-think-directives" tabindex="-1"><a class="header-anchor" href="#thinking-levels-think-directives">#</a> Thinking Levels (/think directives)</h1><h2 id="what-it-does" tabindex="-1"><a class="header-anchor" href="#what-it-does">#</a> What it does</h2><ul><li>Inline directive in any inbound body: <code>/t &lt;level&gt;</code>, <code>/think:&lt;level&gt;</code>, or <code>/thinking &lt;level&gt;</code>.</li><li>Levels (aliases): <code>off | minimal | low | medium | high | xhigh</code> (GPT-5.2 + Codex models only) <ul><li>minimal → “think”</li><li>low → “think hard”</li><li>medium → “think harder”</li><li>high → “ultrathink” (max budget)</li><li>xhigh → “ultrathink+” (GPT-5.2 + Codex models only)</li><li><code>x-high</code>, <code>x_high</code>, <code>extra-high</code>, <code>extra high</code>, and <code>extra_high</code> map to <code>xhigh</code>.</li><li><code>highest</code>, <code>max</code> map to <code>high</code>.</li></ul></li><li>Provider notes: <ul><li>Z.AI (<code>zai/*</code>) only supports binary thinking (<code>on</code>/<code>off</code>). Any non-<code>off</code> level is treated as <code>on</code> (mapped to <code>low</code>).</li></ul></li></ul><h2 id="resolution-order" tabindex="-1"><a class="header-anchor" href="#resolution-order">#</a> Resolution order</h2><ol><li>Inline directive on the message (applies only to that message).</li><li>Session override (set by sending a directive-only message).</li><li>Global default (<code>agents.defaults.thinkingDefault</code> in config).</li><li>Fallback: low for reasoning-capable models; off otherwise.</li></ol><h2 id="setting-a-session-default" tabindex="-1"><a class="header-anchor" href="#setting-a-session-default">#</a> Setting a session default</h2><ul><li>Send a message that is <strong>only</strong> the directive (whitespace allowed), e.g. <code>/think:medium</code> or <code>/t high</code>.</li><li>That sticks for the current session (per-sender by default); cleared by <code>/think:off</code> or session idle reset.</li><li>Confirmation reply is sent (<code>Thinking level set to high.</code> / <code>Thinking disabled.</code>). If the level is invalid (e.g. <code>/thinking big</code>), the command is rejected with a hint and the session state is left unchanged.</li><li>Send <code>/think</code> (or <code>/think:</code>) with no argument to see the current thinking level.</li></ul><h2 id="application-by-agent" tabindex="-1"><a class="header-anchor" href="#application-by-agent">#</a> Application by agent</h2><ul><li><strong>Embedded Pi</strong>: the resolved level is passed to the in-process Pi agent runtime.</li></ul><h2 id="verbose-directives-verbose-or-v" tabindex="-1"><a class="header-anchor" href="#verbose-directives-verbose-or-v">#</a> Verbose directives (/verbose or /v)</h2><ul><li>Levels: <code>on</code> (minimal) | <code>full</code> | <code>off</code> (default).</li><li>Directive-only message toggles session verbose and replies <code>Verbose logging enabled.</code> / <code>Verbose logging disabled.</code>; invalid levels return a hint without changing state.</li><li><code>/verbose off</code> stores an explicit session override; clear it via the Sessions UI by choosing <code>inherit</code>.</li><li>Inline directive affects only that message; session/global defaults apply otherwise.</li><li>Send <code>/verbose</code> (or <code>/verbose:</code>) with no argument to see the current verbose level.</li><li>When verbose is on, agents that emit structured tool results (Pi, other JSON agents) send each tool call back as its own metadata-only message, prefixed with <code>&lt;emoji&gt; &lt;tool-name&gt;: &lt;arg&gt;</code> when available (path/command). These tool summaries are sent as soon as each tool starts (separate bubbles), not as streaming deltas.</li><li>When verbose is <code>full</code>, tool outputs are also forwarded after completion (separate bubble, truncated to a safe length). If you toggle <code>/verbose on|full|off</code> while a run is in-flight, subsequent tool bubbles honor the new setting.</li></ul><h2 id="reasoning-visibility-reasoning" tabindex="-1"><a class="header-anchor" href="#reasoning-visibility-reasoning">#</a> Reasoning visibility (/reasoning)</h2><ul><li>Levels: <code>on|off|stream</code>.</li><li>Directive-only message toggles whether thinking blocks are shown in replies.</li><li>When enabled, reasoning is sent as a <strong>separate message</strong> prefixed with <code>Reasoning:</code>.</li><li><code>stream</code> (Telegram only): streams reasoning into the Telegram draft bubble while the reply is generating, then sends the final answer without reasoning.</li><li>Alias: <code>/reason</code>.</li><li>Send <code>/reasoning</code> (or <code>/reasoning:</code>) with no argument to see the current reasoning level.</li></ul><h2 id="related" tabindex="-1"><a class="header-anchor" href="#related">#</a> Related</h2><ul><li>Elevated mode docs live in <a href="/docs/tools/elevated">Elevated mode</a>.</li></ul><h2 id="heartbeats" tabindex="-1"><a class="header-anchor" href="#heartbeats">#</a> Heartbeats</h2><ul><li>Heartbeat probe body is the configured heartbeat prompt (default: <code>Read HEARTBEAT.md if it exists (workspace context). Follow it strictly. Do not infer or repeat old tasks from prior chats. If nothing needs attention, reply HEARTBEAT_OK.</code>). Inline directives in a heartbeat message apply as usual (but avoid changing session defaults from heartbeats).</li><li>Heartbeat delivery defaults to the final payload only. To also send the separate <code>Reasoning:</code> message (when available), set <code>agents.defaults.heartbeat.includeReasoning: true</code> or per-agent <code>agents.list[].heartbeat.includeReasoning: true</code>.</li></ul><h2 id="web-chat-ui" tabindex="-1"><a class="header-anchor" href="#web-chat-ui">#</a> Web chat UI</h2><ul><li>The web chat thinking selector mirrors the session&#39;s stored level from the inbound session store/config when the page loads.</li><li>Picking another level applies only to the next message (<code>thinkingOnce</code>); after sending, the selector snaps back to the stored session level.</li><li>To change the session default, send a <code>/think:&lt;level&gt;</code> directive (as before); the selector will reflect it after the next reload.</li></ul>',19)])])}const b=i(s,[["render",l]]);export{u as __pageData,b as default};
